import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.unmarshalling.Unmarshal
import akka.stream.Materializer

import scala.concurrent.{ExecutionContext, Future}
import scala.util.{Failure, Success, Try}
import java.net.{InetAddress, URI}

object SecureWebhookProxyService extends App {
  implicit val system: ActorSystem = ActorSystem("webhook-proxy")
  implicit val materializer: Materializer = Materializer(system)
  implicit val executionContext: ExecutionContext = system.dispatcher

  val allowedHosts = Set(
    "api.partner1.com",
    "webhooks.partner2.com",
    "api.partner3.io"
  )

  def isPrivateOrReservedIP(address: InetAddress): Boolean = {
    val bytes = address.getAddress
    
    address.isLoopbackAddress ||
    address.isLinkLocalAddress ||
    address.isMulticastAddress ||
    address.isSiteLocalAddress ||
    address.isAnyLocalAddress ||
    (bytes.length == 4 && (
      (bytes(0) & 0xFF) == 10 ||
      ((bytes(0) & 0xFF) == 172 && (bytes(1) & 0xFF) >= 16 && (bytes(1) & 0xFF) <= 31) ||
      ((bytes(0) & 0xFF) == 192 && (bytes(1) & 0xFF) == 168) ||
      ((bytes(0) & 0xFF) == 169 && (bytes(1) & 0xFF) == 254) ||
      ((bytes(0) & 0xFF) == 127) ||
      ((bytes(0) & 0xFF) == 0) ||
      ((bytes(0) & 0xFF) >= 224)
    )) ||
    (bytes.length == 16 && (
      (bytes(0) & 0xFF) == 0xFE && (bytes(1) & 0xC0) == 0x80 ||
      (bytes(0) & 0xFF) == 0xFE && (bytes(1) & 0xC0) == 0xC0 ||
      (bytes(0) & 0xFF) == 0xFF ||
      bytes.forall(_ == 0) ||
      (bytes(0) & 0xFF) == 0xFC || (bytes(0) & 0xFF) == 0xFD
    ))
  }

  def validateUrl(urlString: String): Either[String, URI] = {
    Try {
      val uri = new URI(urlString)
      
      if (uri.getScheme == null || (!uri.getScheme.equalsIgnoreCase("http") && !uri.getScheme.equalsIgnoreCase("https"))) {
        return Left("Only HTTP and HTTPS schemes are allowed")
      }
      
      val host = uri.getHost
      if (host == null || host.isEmpty) {
        return Left("Invalid or missing host")
      }
      
      if (!allowedHosts.contains(host.toLowerCase)) {
        return Left(s"Host $host is not in the allowlist")
      }
      
      val addresses = InetAddress.getAllByName(host)
      if (addresses.exists(isPrivateOrReservedIP)) {
        return Left(s"Host $host resolves to a private or reserved IP address")
      }
      
      uri
    } match {
      case Success(uri) => Right(uri)
      case Failure(ex) => Left(s"Invalid URL: ${ex.getMessage}")
    }
  }

  def fetchContent(urlString: String): Future[Either[String, String]] = {
    validateUrl(urlString) match {
      case Left(error) => Future.successful(Left(error))
      case Right(uri) =>
        val request = HttpRequest(
          method = HttpMethods.GET,
          uri = uri.toString
        ).withHeaders(
          akka.http.scaladsl.model.headers.`User-Agent`("SecureWebhookProxy/1.0")
        )
        
        Http()
          .singleRequest(
            request,
            settings = akka.http.scaladsl.settings.ConnectionPoolSettings(system)
              .withMaxRedirects(0)
          )
          .flatMap { response =>
            response.status match {
              case StatusCodes.OK =>
                Unmarshal(response.entity).to[String].map(content => Right(content))
              case StatusCodes.MovedPermanently | StatusCodes.Found | 
                   StatusCodes.SeeOther | StatusCodes.TemporaryRedirect | 
                   StatusCodes.PermanentRedirect =>
                response.discardEntityBytes()
                Future.successful(Left("Redirects are not allowed"))
              case _ =>
                response.discardEntityBytes()
                Future.successful(Left(s"Request failed with status: ${response.status}"))
            }
          }
          .recover {
            case ex: Exception => Left(s"Request failed: ${ex.getMessage}")
          }
    }
  }

  case class UrlRequest(url: String)

  import akka.http.scaladsl.marshallers.sprayjson.SprayJsonSupport._
  import spray.json.DefaultJsonProtocol._
  
  implicit val urlRequestFormat = jsonFormat1(UrlRequest)

  val route =
    path("fetch") {
      post {
        entity(as[UrlRequest]) { urlRequest =>
          onComplete(fetchContent(urlRequest.url)) {
            case Success(Right(content)) =>
              complete(HttpResponse(
                status = StatusCodes.OK,
                entity = HttpEntity(ContentTypes.`application/json`, s"""{"status":"success","content":${spray.json.JsString(content).compactPrint}}""")
              ))
            case Success(Left(error)) =>
              complete(HttpResponse(
                status = StatusCodes.BadRequest,
                entity = HttpEntity(ContentTypes.`application/json`, s"""{"status":"error","message":"$error"}""")
              ))
            case Failure(ex) =>
              complete(HttpResponse(
                status = StatusCodes.InternalServerError,
                entity = HttpEntity(ContentTypes.`application/json`, s"""{"status":"error","message":"${ex.getMessage}"}""")
              ))
          }
        }
      }
    }

  val bindingFuture = Http().newServerAt("0.0.0.0", 8080).bind(route)
  
  println("Server online at http://0.0.0.0:8080/")
}